source_sections.text:
{
  "day": "1",
  "heading": "Drive from Shimla to Yangpa",
  "sub_heading": "Drive Distance: 203 km | Drive Duration: 6-7 hours | Pick up point for Indiahikes trekkers: Old Bus Stand, Shimla",
  "details": "Transport will be arranged from Old Bus Stand, Shimla at 6.30 AM. The cost is Rs. 1800/- (additional 5% GST) per trekker for the transfer from Shimla to Yangpa. These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "2",
  "heading": "Trek from Yangpa to Mulling",
  "sub_heading": "Trek Distance: 11 km | Trek Duration: 8 hours | Altitude Gain: 8,275 ft to 10,820 ft",
  "details": "Moderate. Easy walk on motor road for 2.65 km followed by 4.5 km ascent. Level walk for about 1 km then ascend all the way to Mulling."
}

{
  "day": "3",
  "heading": "Trek from Mulling to Karah",
  "sub_heading": "Trek Distance: 6 km | Trek Duration: 5 hours | Altitude Gain: 10,820 ft to 11,590 ft",
  "details": "Moderate. Gradual ascent for 3.3 km followed by 1.5 km of steep ascent, easing off at the last 1.2 km."
}

{
  "day": "4",
  "heading": "Trek from Karah to Phutsirang",
  "sub_heading": "Trek Distance: 5 km | Trek Duration: 4 hours | Altitude Gain: 11,590 ft to 13,485 ft",
  "details": "Moderate. Steep ascent throughout."
}

{
  "day": "5",
  "heading": "Acclimatization and rest day at Phutsirang",
  "sub_heading": "",
  "details": ""
}

{
  "day": "6",
  "heading": "Trek from Phutsirang to Bwalder via Pin Bhaba Pass",
  "sub_heading": "Trek Distance: 15 km | Trek Duration: 12 hours | Altitude Gain and Loss: 13,485 ft to 13,435 ft via 16,105 ft",
  "details": "Difficult. Steep ascent for close to 4 km to reach the pass, followed by a river crossing and gradual descent through moraine, rocks and scree all the way to the campsite."
}

{
  "day": "7",
  "heading": "Trek from Bwalder to Mudh",
  "sub_heading": "Trek Distance: 13 km | Trek Duration: 7 hours | Altitude Loss: 13,435 ft to 12,420 ft",
  "details": "Moderate. Gradual ascents, descents and flat walks through moraine and rocks."
}

{
  "day": "8",
  "heading": "Drive back from Mudh to Manali",
  "sub_heading": "Drive Distance: 232 km | Drive Duration: 7-8 hours | Drop off point Indiahikes trekkers: Beas Bridge, Manali",
  "details": "Transport will be arranged from Mudh to Beas Bridge in Manali. The cost is Rs. 2700/- (additional 5% GST) per trekker for the transfer from Mudh to Manali. These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "9",
  "heading": "Buffer Day",
  "sub_heading": "It is mandatory to have this extra day as any bad weather or rain will delay your pass crossing. If buffer day is utilized, you will need to pay Rs.2,500 + 5% GST. This amount is to be handed over to your Trek Leader.",
  "details": "Please note: The distance between campsites may vary by 100 meters depending the weather conditions and the route you take. The altitude may also vary by 100 feet for similar reasons."
}
